from collections import defaultdict

class Solution:
    def findHighAccessEmployees(self, access_times):
        times = defaultdict(list)
        for name, t in access_times:
            minutes = int(t[:2]) * 60 + int(t[2:])
            times[name].append(minutes)
        result = []
        for name, lst in times.items():
            lst.sort()
            n = len(lst)
            for i in range(n - 2):
                if lst[i + 2] - lst[i] < 60:
                    result.append(name)
                    break
        return result

