var findHighAccessEmployees = function(access_times) {
    const times = new Map();
    for (const [name, t] of access_times) {
        const minutes = parseInt(t.slice(0, 2), 10) * 60 + parseInt(t.slice(2), 10);
        if (!times.has(name)) times.set(name, []);
        times.get(name).push(minutes);
    }
    const result = [];
    for (const [name, lst] of times) {
        lst.sort((a, b) => a - b);
        for (let i = 0; i + 2 < lst.length; i++) {
            if (lst[i + 2] - lst[i] < 60) {
                result.push(name);
                break;
            }
        }
    }
    return result;
};
